+fn glyph_width(ch: char, cjk_width: bool) -> usize {
+    if ch.is_ascii() {
+        return match ch {
+            '\t' | '\n' | '\r' => 1,
+            ' '..='~' => 1,
+            _ => 0,
+        };
+    }
+    if cjk_width {
+        ch.width_cjk().unwrap_or(0)
+    } else {
+        ch.width().unwrap_or(0)
+    }
+}
